info.narration:
[
{มีหนังสือเล่มหนึ่งที่ทำจากกระดาษหนังโบราณ},
{มันค่อนข้างหนา แต่ทุกหน้าของหนังสือว่างเปล่า},
{มีหนังสือเล่มหนึ่งที่ดูเหมือนหน้าปกจะขาดได้หากหยิบจับอย่างไม่ระมัดระวัง }
]

[
{#0 เป็นคนที่อ่านหนังสือบ่อย แต่ #0 รู้สึกว่านี่ไม่ใช่หนังสือที่ควรค่าแก่การอ่าน },
{#0 ไม่ได้อ่านหนังสือบ่อยนัก แต่มีความอยากประหลาดๆ ที่อยากจะพลิกหน้ากระดาษ},
{#0 เป็นคนที่ไม่เคยไปห้องสมุด แต่มีความอยากประหลาดๆ ที่อยากจะพลิกหน้ากระดาษ}
]

observe.desc:
      [
      {เป็นสมุดบันทึกขนาดฝ่ามือ ทุกหน้าเต็มไปด้วยลายมือที่เขียนหวัดๆ การวิเคราะห์ระบุว่าตัวอักษรเป็นบทละครที่ไม่ทราบว่าใครเป็นคนเขียนและเขียนเมื่อไหร่
บทนี้เกี่ยวกับชายคนหนึ่งที่เติบโตมาในครอบครัวธรรมดา วันหนึ่ง เขาหยิบหน้ากากจากถนนและลงมือฆ่าคนรู้จักทั้งหมดอย่างหุนหันพลันแล่น เมื่อคนใดสัมผัสกับสิ่งมีชีวิตนี้ บุคคลนั้นจะแสดงพฤติกรรมเดียวกับชายในบทที่กล่าวมาข้างต้น เช่นเดียวกับในเรื่องราว บุคคลที่ได้รับผลกระทบอาจพยายามฆ่าคนรอบข้าง บุคคลนั้นเชื่อว่าตัวเองเป็นตัวเอกของเรื่อง }
      ]

      [
      {ชื่อเรื่อง: Peccatum Proprium 
 วันนี้ เราจะแสดงต่อหน้าพระราชา 
ตัวละคร : A, The Failed, The Abandoned, The Broken, The Coward, และ…….}
      ]

      [
      {พบศพในแผนก [ข้อมูลถูกเซ็นเซอร์] ผู้กระทำผิดสารภาพทันทีที่ทำผิดพิลึกไปกว่านั้น พยานเพียงคนเดียวในที่เกิดเหตุไม่ได้พยายามหยุดอาชญากรรมหรือแม้แต่โทรแจ้งเจ้าหน้าที่ในช่วงที่ A เสียชีวิต นอกจากนี้ยังไม่มีแรงจูงใจที่ชัดเจนสำหรับอาชญากรรม ไม่มีความบาดหมางระหว่างกันเลย เหยื่อและผู้โจมตีเป็นเพื่อนกันในแผนกเดียวกัน คำให้การของพวกเขานั้นแปลกประหลาดมาก ผู้โจมตีไม่รู้ตัวว่าเขากำลังก่อเหตุฆาตกรรมในช่วงที่เขากระทำอาชญากรรม เขาอ้างว่าคิดว่ามันเป็นเพียงการแสดงในละครเท่านั้น คำให้การของพยาน C คือ C รู้ดีว่า A จะถูก B ฆาตกรรม แต่ยืนยันว่ามันเป็นสิ่งที่หลีกเลี่ยงไม่ได้เพื่อจบละคร
ฝ่ายหนึ่งโต้แย้งว่าพวกเขากำลังแสดงพิธีกรรมทางศาสนาลึกลับบางอย่าง ในขณะที่อีกฝ่ายโต้แย้งว่าทั้งคู่กำลังป่วยด้วยอาการทางจิต
ระหว่างการสอบสวนเมื่อที่ปรึกษาถามว่า “คุณคิดว่ามันเป็นละครเหรอ? แล้วมันแสดงให้ใครดู?” พวกเขาทั้งคู่เงยหน้าขึ้นพร้อมกัน นี่ไม่ใช่คำให้การจริง จึงไม่ได้รับการบันทึกอย่างเป็นทางการ }
      ]

max.desc:
[
{ละครได้เริ่มต้นขึ้นนานแล้ว}
{นี่คือชายผู้สังหารคนมากมาย }
{และคุณกำลังถือปืน}
]

[
{คุณตัดสินใจยิงชายคนนั้น}
{ในที่สุดม่านก็ปิดลง}
]

[
{ปลายกระบอกปืนหลงทาง}
{ละครจบลงด้วยโศกนาฏกรรม}
]

[
{เมื่อผู้บริสุทธิ์ตาย}
{ละครจบลงด้วยเรื่องตลก}
]

max.angela:
[
{“คนบาปถูกเขย่าด้วยบรรยากาศที่แปลกประหลาดของเวที และสารภาพบาปของเขา บทละครคือสิ่งที่ทำให้คนซื่อสัตย์มากขึ้น” }
]
